import sys
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
sys.path.insert(0, str(ROOT / "backend"))


def test_report_target_price_detection_detects_nested_explicit_targets():
    from report_target_price_detection import detect_explicit_target_price_fields

    fields = detect_explicit_target_price_fields(
        {
            "parsed": {
                "recommendation": {
                    "target_price": "NT$120",
                    "commentary": "no explicit target here",
                },
                "price_targets": {
                    "base": 110,
                    "bear": "資料不足",
                },
            },
            "structured_outputs": {
                "final": {"12個月": "NT$130"},
            },
        }
    )

    assert fields == [
        "parsed.price_targets.base",
        "parsed.recommendation.target_price",
        "structured_outputs.final.12個月",
    ]


def test_report_target_price_detection_ignores_ranges_insufficient_and_non_finite_values():
    from report_target_price_detection import detect_explicit_target_price_fields

    fields = detect_explicit_target_price_fields(
        {
            "parsed": {
                "recommendation": {
                    "range_target_price": "NT$100-120",
                    "to_range_target_price": "target price 100 to 120",
                    "and_range_target_price": "target price between 100 and 120",
                    "chinese_and_range_target_price": "目標價介於100與120元",
                    "wave_range_target_price": "NT$100〜120",
                    "fullwidth_minus_range_target_price": "NT$100－120",
                    "insufficient_target_price": "資料不足",
                    "nan_target_price": float("nan"),
                    "inf_target_price": float("inf"),
                    "negative_number_target_price": -120,
                    "zero_number_target_price": 0,
                    "negative_text_target_price": "-120",
                    "negative_currency_target_price": "NT$-120",
                    "zero_text_target_price": "0",
                    "zero_currency_target_price": "NT$0",
                    "overflow_text_target_price": "NT$1e309",
                    "valid_target_price": 120.5,
                }
            }
        }
    )

    assert fields == ["parsed.recommendation.valid_target_price"]


